mapper.select:
SELECT COUNT(*)
FROM board_comment
WHERE target_type = #{targetType}
  AND target_id   = #{targetId}

mapper.update:
UPDATE board_comment
   SET content = #{content},
       mod_dt  = SYSDATE
 WHERE comment_id = #{commentId}
   AND member_id  = #{memberId}

mapper.delete:
DELETE FROM board_comment
WHERE comment_id = #{commentId}
  AND member_id  = #{memberId}

DELETE FROM board_comment
WHERE target_type = #{targetType}
  AND target_id   = #{targetId}
